INSERT INTO "public"."application" ("name", "description", "icon", "tag", "classify") VALUES ( 'Tiny Design 设计体系', '华为云产品和服务的规范体系，包括交互视觉设计、业务流程、国际化、术语词条。', 'card-list-application-default.png', '[{ \"type\": \"\", \"value\": \"机会点定义\" }, { \"type\": \"danger\", \"value\": \"交互设计\" }]', 'design');
INSERT INTO "public"."application" ("name", "description", "icon", "tag", "classify") VALUES ( 'Tiny DesignLink 设计流水线工具', '设计+协同+资源管理，一个工具就够了，在线原型设计、设计过程融入DevOps流程。', 'card-list-application-default.png', '[{ \"type\": \"error\", \"value\": \"交互设计\" }, { \"type\": \"warning\", \"value\": \"视觉设计\" }]', 'design');
INSERT INTO "public"."application" ("name", "description", "icon", "tag", "classify") VALUES ( 'TinyUI3.0 开发工具 ', 'Cloud Design System 提供了丰富的规范文档及开发组件。', 'card-list-application-default.png', '[{ \"type\": \"success\", \"value\": \"开发\" }]', 'dev');
INSERT INTO "public"."application" ("name", "description", "icon", "tag", "classify") VALUES ( 'TinyPlus3.0 开发工具', 'TinyPlus3.0 是基于Angular + Typescript的Web前端云业务组件库。', 'card-list-tiny-plus.png', '[{ \"type\": \"success\", \"value\": \"开发\" }]', 'dev');
INSERT INTO "public"."application" ("name", "description", "icon", "tag", "classify") VALUES ( 'Tiny Stage 工程工具 ', '一个跨平台的前端工程化cli工具，为开发提供一系列开发套件和工程插件', 'card-list-console-framework.png', '[{ \"type\": \"success\", \"value\": \"开发\" }]', 'dev');
INSERT INTO "public"."application" ("name", "description", "icon", "tag", "classify") VALUES ( 'Tiny Flow 接口编排工具 ', '端到端的API编排解决方案，通过可视化编程的方式快速生成、发布、调试的API编排。', 'card-list-console-framework.png', '[{ \"type\": \"success\", \"value\": \"开发\" }]', 'dev');
INSERT INTO "public"."application" ("name", "description", "icon", "tag", "classify") VALUES ( 'Tiny Gate 门禁系统', '门禁系统，通过卡点方式集成到伏羲流水线，在服务发布时生成预览页面。', 'card-list-console-framework.png', '[{ \"type\": \"info\", \"value\": \"测试验证\" }]', 'dev');
INSERT INTO "public"."application" ("name", "description", "icon", "tag", "classify") VALUES ( 'Console Framework 控制台框架', '华为云各服务快速构建管理控制台的平台。', 'card-list-console-framework.png', '[{ \"type\": \"success\", \"value\": \"开发\" },{ \"type\": \"info\", \"value\": \"测试验证\" },{ \"type\": \"warning\", \"value\": \"上线\" }]', 'dev');
INSERT INTO "public"."application" ("name", "description", "icon", "tag", "classify") VALUES ( 'Nodejs Framework Nodejs应用', '基于egg的定制化web服务框架，让你快速上手Nodejs做BFF意见微服务。', 'card-list-console-framework.png', '[{ \"type\": \"success\", \"value\": \"开发\" },{ \"type\": \"info\", \"value\": \"测试验证\" }]', 'dev');
INSERT INTO "public"."application" ("name", "description", "icon", "tag", "classify") VALUES ( 'Furion 前端体验监控', '提供端到端前端用户体验度量，让产品用户体验可度量、可监控、可优化。', 'card-list-furion.png', '[{ \"type\": \"\", \"value\": \"机会点定义\" }]', 'dev');
INSERT INTO "public"."application" ("name", "description", "icon", "tag", "classify") VALUES ( 'Tiny Mock API 管理', '功能强大的API管理平台，旨在为开发、产品、测试人员提供更优雅的接口管理服务。', 'card-list-application-default.png', '[{ \"type\": \"success\", \"value\": \"开发\" },{ \"type\": \"warning\", \"value\": \"视觉设计\" }]', 'dev');
